classDiagram(name = "BankModel") {
    val account = classOf(name = "Account") {
        isAbstract = true
        attribute(name = "IBAN", type = "String", isReadOnly = true)
        attribute(name = "balance", type = "Double", isReadOnly = false)
    }
    val checkingAccount = classOf(name = "CheckingAccount") {
        extends(general = account)
        attribute(name = "overdraftLimit", type = "Double", isReadOnly = false)
    }
    val savingsAccount = classOf(name = "SavingsAccount") {
        extends(general = account)
        attribute(name = "interestRate", type = "Double", isReadOnly = false)
    }
    val interestContract = classOf(name = "InterestContract") {
        operation(name = "calculateInterest") { parameter(name = "balance", type = "Double"); returns(typeName = "Double") }
    }
    val transaction = classOf(name = "Transaction") {
        attribute(name = "amount", type = "Double", isReadOnly = true)
        attribute(name = "timestamp", type = "Date", isReadOnly = true)
        attribute(name = "type", type = "String", isReadOnly = true)
    }
    val customer = classOf(name = "Customer") {
        attribute(name = "name", type = "String", isReadOnly = false)
    }
    association(source = customer, target = account) {
        aggregation = AggregationKind.NONE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "accounts" }
    }
    association(source = account, target = transaction) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "transactions" }
    }
    association(source = savingsAccount, target = interestContract) {
        aggregation = AggregationKind.NONE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "interestContract" }
    }
}

