@startuml
abstract class Payment {
    amount
    date
}
class MembershipFeePayment {
    contributionYear
}
class Donation {
    earmarkedCampaign
}
class Member {
    status
}
class MembershipApplication {
    applicationStatus
}
class DistrictChapter
class StateChapter
class Committee
class Mandate {
    termOfOffice
}
class Campaign
class Deployment {
    hours
}
interface NotificationContract

Payment <|-- MembershipFeePayment
Payment <|-- Donation
Member "1" o-- "0..*" Payment : payments
DistrictChapter "1" *-- "0..*" Member : members
StateChapter "1" *-- "0..*" DistrictChapter : districtChapters
DistrictChapter "1" *-- "0..*" MembershipApplication : applications
MembershipApplication "1" -- "1" Member : emerges
Committee "1" *-- "0..*" Mandate : mandates
Mandate "1" -- "1" Member : awardedTo
DistrictChapter "1" *-- "0..*" Campaign : campaigns
Campaign "1" *-- "0..*" Deployment : deployments
Deployment "1" -- "1" Member : participant
Member "1" ..|> NotificationContract
@enduml

classDiagram(name = "MembershipManagementSystem") {
    val stateChapter = classOf(name = "StateChapter")
    val districtChapter = classOf(name = "DistrictChapter")
    val member = classOf(name = "Member") {
        attribute(name = "status", type = "String")
    }
    val membershipApplication = classOf(name = "MembershipApplication") {
        attribute(name = "applicationStatus", type = "String")
    }
    val notificationContract = classOf(name = "NotificationContract")
    val committee = classOf(name = "Committee")
    val mandate = classOf(name = "Mandate") {
        attribute(name = "termOfOffice", type = "String")
    }
    val campaign = classOf(name = "Campaign")
    val deployment = classOf(name = "Deployment") {
        attribute(name = "hours", type = "Int")
    }
    val payment = classOf(name = "Payment") {
        isAbstract = true
        attribute(name = "amount", type = "Double")
        attribute(name = "date", type = "String")
    }
    val membershipFeePayment = classOf(name = "MembershipFeePayment") { extends(general = payment) }
    val donation = classOf(name = "Donation") {
        extends(general = payment)
        attribute(name = "earmarkedCampaign", type = "Campaign?")
    }

    association(source = stateChapter, target = districtChapter) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "districts" }
    }
    association(source = districtChapter, target = member) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "members" }
    }
    association(source = membershipApplication, target = districtChapter) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "submittedTo" }
    }
    association(source = membershipApplication, target = member) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "resultingMember" }
    }
    association(source = member, target = notificationContract) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "contact" }
    }
    association(source = committee, target = mandate) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "mandates" }
    }
    association(source = mandate, target = member) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "holder" }
    }
    association(source = districtChapter, target = campaign) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "campaigns" }
    }
    association(source = campaign, target = deployment) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "deployments" }
    }
    association(source = deployment, target = member) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "participant" }
    }
    association(source = payment, target = member) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "payer" }
    }
}

